import axios from 'axios';

const API_BASE_URL = 'http://localhost:5033/api';

const api = axios.create({
  baseURL: API_BASE_URL,
  headers: {
    'Content-Type': 'application/json',
    'Accept': 'application/json'
  }
});

// Request Interceptor - Attach JWT token
api.interceptors.request.use(
  (config) => {
    const token = sessionStorage.getItem('token') || localStorage.getItem('token');
    if (token) {
      config.headers = config.headers || {};
      config.headers.Authorization = `Bearer ${token}`;
    }
    return config;
  },
  (error) => Promise.reject(error)
);

// Response Interceptor
api.interceptors.response.use(
  (response) => response,
  (error) => {
    if (error.response?.status === 401) {
      console.error('Unauthorized - clearing tokens');
      sessionStorage.removeItem('token');
      localStorage.removeItem('token');
    }
    return Promise.reject(error);
  }
);

// ===================== AUTH API =====================
export const authAPI = {
  login: async (email, password) => api.post('/auth/login', { email, password }),
  register: async (fullName, email, mobile, password) => 
    api.post('/auth/register', { fullName, email, mobile, password }),
  getProfile: () => api.get('/user/profile'),
  requestOtp: async (mobile) => api.post('/auth/request-otp', { mobile }),
  verifyOtp: async (mobile, otp) => api.post('/auth/verify-otp', { mobile, otp }),
  requestEmailOtp: async (email) => api.post('/auth/request-email-otp', { email }),
  verifyEmailOtp: async (email, otp) => api.post('/auth/verify-email-otp', { email, otp })
};

// ===================== MONGODB AUTH API =====================
export const mongoAuthAPI = {
  login: async (email, password) => api.post('/mongo/auth/login', { email, password }),
  register: async (fullName, email, mobile, password, gender) => 
    api.post('/mongo/auth/register', { fullName, email, mobile, password, gender }),
  requestOtp: async (mobile) => api.post('/mongo/auth/request-otp', { mobile }),
  verifyOtp: async (mobile, otp) => api.post('/mongo/auth/verify-otp', { mobile, otp }),
  requestEmailOtp: async (email) => api.post('/mongo/auth/request-email-otp', { email }),
  verifyEmailOtp: async (email, otp) => api.post('/mongo/auth/verify-email-otp', { email, otp })
};

// ===================== PRODUCTS API (SQL - FOR CRUD) =====================
export const productsAPI = {
  // ✅ READ Operations
  getAll: () => api.get('/products'),
  search: (query) => api.get('/products/search', { params: { query: query || '' } }),
  getById: (id) => api.get(`/products/${id}`),

  // ✅ WRITE Operations (Admin only, uses SQL ProductsController)
  create: (productData) => {
    console.log('📦 Creating product:', productData);
    return api.post('/products', productData);
  },

  update: (id, productData) => {
    console.log('✏️ Updating product:', id, productData);
    return api.put(`/products/${id}`, productData);
  },

  delete: (id) => {
    console.log('🗑️ Deleting product:', id);
    return api.delete(`/products/${id}`);
  }
};

// ===================== CART API =====================
export const cartAPI = {
  view: (userId) => {
    if (!userId) throw new Error('User ID is required');
    return api.get(`/cart/user/${userId}`);
  },
  add: (userId, data) => {
    if (!userId || !data?.productId) throw new Error('User ID and Product ID required');
    return api.post(`/cart/user/${userId}/items`, {
      productId: data.productId,
      quantity: data.quantity || 1
    });
  },
  update: (userId, productId, quantity) => {
    if (!userId || !productId) throw new Error('User ID and Product ID required');
    return api.put(`/cart/user/${userId}/items/${productId}`, { quantity });
  },
  remove: (userId, productId) => {
    if (!userId || !productId) throw new Error('User ID and Product ID required');
    return api.delete(`/cart/user/${userId}/items/${productId}`);
  },
  clear: (userId) => {
    if (!userId) throw new Error('User ID is required');
    return api.delete(`/cart/user/${userId}`);
  }
};

// ===================== ORDERS API (MongoDB) =====================
export const ordersAPI = {
  confirm: (shippingAddressId) => {
    const userId = getUserIdFromToken();
    if (!userId) return Promise.reject(new Error('User ID required. Please login again.'));
    if (!shippingAddressId) return Promise.reject(new Error('Shipping Address ID required'));

    const mongoObjectIdRegex = /^[0-9a-f]{24}$/i;
    if (!mongoObjectIdRegex.test(shippingAddressId)) {
      return Promise.reject(new Error('Invalid Shipping Address ID format'));
    }

    return api.post('/mongo/order/confirm', { ShippingAddressId: shippingAddressId });
  },
  history: () => api.get('/mongo/order/history'),
  getById: (mongoId) => api.get(`/mongo/order/${mongoId}`),
  getByOrderNumber: (orderNumber) => api.get(`/mongo/order/order-number/${orderNumber}`),
  cancel: (mongoId) => api.post(`/mongo/order/${mongoId}/cancel`)
