// ===================== ADMIN API - FIXED =====================
export const adminAPI = {
  // ===== MONGODB ADMIN ENDPOINTS (Analytics & Reports) =====

  // User Management
  getUsers: () => {
    console.log('👥 Admin API - Getting users from MongoDB');
    return api.get('/mongo/admin/users');
  },
  getUserById: (mongoId) => api.get(`/mongo/admin/users/${mongoId}`),

  // Order Management
  getOrders: () => {
    console.log('📦 Admin API - Getting orders from MongoDB');
