  // Stock & Inventory
  getStockAnalysis: () => api.get('/mongo/admin/stock-analysis'),

  // Customer Analytics
  getCustomerInsights: () => api.get('/mongo/admin/customer-insights'),

  // Metrics
  getDailyMetrics: (startDate, endDate) => 
    api.get('/mongo/admin/daily-metrics', { params: { startDate, endDate } }),

  // Dashboard
  getDashboard: () => api.get('/mongo/admin/dashboard'),

  // ===== PRODUCT CRUD (Uses SQL ProductsController) =====

  // ✅ FIX: Use productsAPI for CRUD operations
  createProduct: (productData) => {
    console.log('➕ Admin API - Creating product via ProductsController');
    return productsAPI.create(productData);
  },

  updateProduct: (productId, productData) => {
    console.log('✏️ Admin API - Updating product via ProductsController');
    return productsAPI.update(productId, productData);
  },

  deleteProduct: (productId) => {
    console.log('🗑️ Admin API - Deleting product via ProductsController');
    return productsAPI.delete(productId);
  },

  // Legacy SQL endpoints (kept for backward compatibility)
  getLowStockProducts: () => api.get('/admin/inventory/low-stock'),
  getStockByCategory: (category) => api.get(`/admin/inventory/category/${category}`),
  updateStock: (productId, quantity) => api.put('/admin/inventory/update', { productId, quantity })
};

// ===================== OTHER APIs =====================
export const addressAPI = {
  getAll: () => api.get('/user/addresses'),
  add: async (address) => (await api.post('/user/addresses', address)).data,
  update: async (id, address) => (await api.put(`/user/addresses/${id}`, address)).data,
  remove: async (id) => (await api.delete(`/user/addresses/${id}`)).data
};

export const recommendationsAPI = {
  rank: (productIds, criteria) => api.post('/recommendations/rank', { productIds, criteria })
};

export const inventoryAPI = {
  getStock: (productId) => api.get(`/inventory/stock/${productId}`),
  checkAvailability: (productId, quantity) => 
    api.get('/inventory/check', { params: { productId, quantity } })
};

export const paymentAPI = {
  initiate: (orderId, paymentMethod) => {
    if (!orderId) return Promise.reject(new Error('Order ID is required'));
    return api.post('/mongo/payment/initiate', { orderId, paymentMethod });
  },
  verify: (razorpayOrderId, razorpayPaymentId, razorpaySignature, orderId) => {
    if (!razorpayOrderId || !razorpayPaymentId || !razorpaySignature) {
      return Promise.reject(new Error('Payment verification details required'));
    }
    return api.post('/mongo/payment/verify', { 
      razorpayOrderId, razorpayPaymentId, razorpaySignature, orderId 
    });
  },
  getStatus: (orderId) => api.get(`/mongo/payment/status/${orderId}`)
};

export const migrationAPI = {
  migrateUsers: async () => api.post('/migration/migrate-users'),
  verifyMigration: async () => api.get('/migration/verify-migration')
};

// ===================== HELPERS =====================
export const getUserIdFromToken = () => {
  const token = sessionStorage.getItem('token') || localStorage.getItem('token');
  if (!token) return null;

  try {
    const payload = JSON.parse(atob(token.split('.')[1]));
    return payload.nameid || 
           payload['http://schemas.xmlsoap.org/ws/2005/05/identity/claims/nameidentifier'] ||
           payload.sub ||
           payload.userId;
  } catch (error) {
    console.error('Error extracting user ID from token:', error);
    return null;
